class n extends HTMLElement{constructor(){super(),this.miniCart=document.querySelector(".mini-cart")}open(){const e=document.querySelector(".featured-product-media");this.miniCart.classList.toggle("-open"),e==null||e.pause()}close(){}renderContents(e){this.productId=e.id,this.getSectionsToRender().forEach(t=>{document.getElementById(t.id).innerHTML=this.getSectionInnerHTML(e.sections[t.id],t.selector)}),this.open()}getSectionsToRender(){return[{id:"cart-icon-bubble"},{id:"mini-cart-badge"},{id:"main-cart-items",selector:"#main-cart-items"},{id:"main-cart-footer",selector:"#main-cart-footer"}]}getSectionInnerHTML(e,t=".shopify-section"){return new DOMParser().parseFromString(e,"text/html").querySelector(t).innerHTML}setActiveElement(e){this.activeElement=e}}customElements.define("cart-notification",n);
